import React from 'react';
import { Link } from 'react-router-dom';
import TopicsManager from './TopicsManager';
import './Sidebar.css';

function Sidebar({ blogs, loading, topics, onTopicsChange }) {
  return (
    <aside className="sidebar">
      <div className="sidebar-top">
        <div className="sidebar-title">Navigation</div>
        <nav className="sidebar-nav">
          <Link to="/" className="sidebar-item">Home</Link>
          <Link to="/create" className="sidebar-item sidebar-create">+ New Post</Link>
        </nav>
      </div>

      <div className="sidebar-middle">
        <div className="sidebar-topic-label">Blog posts</div>
        {loading ? (
          <div className="sidebar-loading">Loading posts...</div>
        ) : (
          <nav className="sidebar-blog-list">
            {blogs.length === 0 ? (
              <div className="sidebar-empty">No posts yet</div>
            ) : (
              blogs.map(blog => (
                <Link
                  key={blog.id}
                  to={`/blog/${blog.id}`}
                  className="sidebar-blog-link"
                >
                  {blog.title}
                </Link>
              ))
            )}
          </nav>
        )}
      </div>

      <div className="sidebar-bottom">
        <div className="sidebar-topic-label">Topics</div>
        <TopicsManager topics={topics} onTopicsChange={onTopicsChange} />
      </div>
    </aside>
  );
}

export default Sidebar;
